import{_ as r,c as o,o as s,ag as n}from"./chunks/framework.XjE0kKti.js";const g="/gatewayweb/docs/assets/tunnel_architecture.lGhag527.svg",a="/gatewayweb/docs/assets/hub0062-client-list.BXJkgztB.png",d="/gatewayweb/docs/assets/hub0062-client-context-menu.BjYivqls.png",e="/gatewayweb/docs/assets/hub0062-service-list.D5Ft21Y5.png",h="/gatewayweb/docs/assets/hub0062-service-add-dialog-basic.C0q570A8.png",l="/gatewayweb/docs/assets/hub0062-select-client-modal.DdUXeCLG.png",i="/gatewayweb/docs/assets/hub0062-service-add-dialog-address.D6Jj-WHF.png",f=JSON.parse('{"title":"隧道客户端（hub0062）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0062.md","filePath":"modules/hub0062.md","lastUpdated":1776841524000}'),b={name:"modules/hub0062.md"};function u(c,t,p,m,P,q){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="隧道客户端-hub0062" tabindex="-1">隧道客户端（hub0062） <a class="header-anchor" href="#隧道客户端-hub0062" aria-label="Permalink to &quot;隧道客户端（hub0062）&quot;">​</a></h1><p>本模块维护的是 <strong>单独部署的隧道客户端服务</strong>（典型形态类似 FRP 的 <strong>frpc</strong>）：进程运行在内网或业务主机上，使用此处配置的参数 <strong>主动连接远程 <a href="./hub0060.html">隧道服务器（hub0060）</a></strong> 的控制端口；在控制连接之上，再把 <strong>本机已监听的端口服务</strong>（如内网 Web、SSH、MQ 等）按「隧道服务」条目注册到服务端，从而在 <strong>隧道服务端</strong> 一侧获得公网或出口网络可达的 <strong>远程端口、子域名或自定义域名</strong> 等访问入口。</p><p>控制台负责 <strong>客户端与服务条目的持久化配置</strong>、<strong>连接/断开/删除</strong> 等运维操作；实际转发仍由 <strong>客户端进程 + 服务端进程</strong> 协同完成。</p><hr><h2 id="架构与数据流" tabindex="-1">架构与数据流 <a class="header-anchor" href="#架构与数据流" aria-label="Permalink to &quot;架构与数据流&quot;">​</a></h2><p>下图概括 <strong>互联网用户 → 隧道服务端 → 隧道客户端 → 内网本地服务</strong> 的关系（控制面与数据面与常见 FRP 模型一致；图中「静态映射」对应 <strong><a href="./hub0061.html">静态映射（hub0061）</a></strong> 能力，与本文「动态注册的隧道服务」可并存于同一套隧道体系中）。</p><p><img src="'+g+'" alt="内网穿透架构示意（FRP Tunnel）"></p><table tabindex="0"><thead><tr><th>角色</th><th>说明</th></tr></thead><tbody><tr><td><strong>隧道服务端</strong></td><td>部署在公网或统一出口，配置见 <strong><a href="./hub0060.html">hub0060</a></strong>；提供控制端口、数据端口及 HTTP/TCP/UDP 等转发。</td></tr><tr><td><strong>隧道客户端</strong></td><td><strong>与控制台分离部署</strong> 的长驻服务，按本模块中的 <strong>服务器地址、端口、Token</strong> 等连接上述服务端。</td></tr><tr><td><strong>隧道服务</strong></td><td>在 <strong>服务管理</strong> 中配置：声明 <strong>本地地址与端口</strong>（内网真实监听点）以及希望在服务端暴露的 <strong>远程端口/域名</strong> 等，由客户端向服务端注册后生效。</td></tr></tbody></table><p>页面左侧为 <strong>Tab</strong>：<strong>客户端管理</strong>、<strong>服务管理</strong>。</p><p><img src="'+a+'" alt="客户端管理：工具栏、筛选、统计与列表"></p><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>隧道管理</strong> → <strong>隧道客户端</strong>。</p><hr><h2 id="客户端管理" tabindex="-1">客户端管理 <a class="header-anchor" href="#客户端管理" aria-label="Permalink to &quot;客户端管理&quot;">​</a></h2><h3 id="加载与统计" tabindex="-1">加载与统计 <a class="header-anchor" href="#加载与统计" aria-label="Permalink to &quot;加载与统计&quot;">​</a></h3><ul><li>进入 <strong>客户端管理</strong> 标签后，会 <strong>自动加载</strong> 客户端分页列表，并请求顶部 <strong>统计卡片</strong>（总客户端数、已连接、已断开、连接中、错误、总服务数；文案来自模块 i18n，与界面一致）。</li><li>点击 <strong>查询</strong> 会按筛选条件重新拉取列表并再次刷新统计；<strong>重置</strong> 清空条件后查询。</li></ul><h3 id="筛选项" tabindex="-1">筛选项 <a class="header-anchor" href="#筛选项" aria-label="Permalink to &quot;筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>客户端名称</strong></td><td>占位：请输入客户端名称。</td></tr><tr><td><strong>服务器地址</strong></td><td>占位：请输入服务器地址。</td></tr><tr><td><strong>连接状态</strong></td><td>全部 / <strong>已连接</strong> / <strong>已断开</strong> / <strong>连接中</strong> / <strong>错误</strong>。</td></tr><tr><td><strong>状态</strong></td><td>全部 / <strong>启用</strong> / <strong>禁用</strong>（对应配置中的活动标记）。</td></tr></tbody></table><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增客户端</strong></td><td>打开「新增隧道客户端」表单弹窗。</td></tr><tr><td><strong>连接</strong></td><td>取 <strong>已勾选行</strong>；若无勾选，则取 <strong>当前高亮（点击）行</strong>。对 <strong>一条</strong> 客户端发起连接。</td></tr><tr><td><strong>断开</strong></td><td>同上规则，断开 <strong>一条</strong> 客户端连接。</td></tr><tr><td><strong>删除</strong></td><td>同上规则，删除 <strong>一条</strong> 客户端记录（具体是否二次确认以后端与弹窗为准）。</td></tr><tr><td><strong>查询</strong> / <strong>重置</strong></td><td>与筛选表单联动。</td></tr></tbody></table><p><strong>编辑</strong> 未放在工具栏，请通过表格 <strong>右键菜单</strong> 进入编辑。</p><h3 id="表格列-主要" tabindex="-1">表格列（主要） <a class="header-anchor" href="#表格列-主要" aria-label="Permalink to &quot;表格列（主要）&quot;">​</a></h3><p>含 <strong>勾选</strong> 与 <strong>序号</strong>。数据列包括：<strong>客户端 ID</strong>、<strong>客户端名称</strong>、<strong>服务器地址</strong>（地址与端口拼接）、<strong>连接状态</strong>（标签）、<strong>TLS</strong>（启用/禁用文案）、<strong>自动重连</strong>（启用/禁用）、<strong>服务数量</strong>、<strong>重连次数</strong>、<strong>最后连接时间</strong>、<strong>最后心跳</strong>、<strong>状态</strong>（启用/禁用标签）、<strong>创建时间</strong> 等；底部分页。</p><h3 id="客户端表单弹窗-新增-编辑-查看" tabindex="-1">客户端表单弹窗（新增 / 编辑 / 查看） <a class="header-anchor" href="#客户端表单弹窗-新增-编辑-查看" aria-label="Permalink to &quot;客户端表单弹窗（新增 / 编辑 / 查看）&quot;">​</a></h3><p>标题为 <strong>新增隧道客户端</strong>、<strong>编辑隧道客户端</strong>、<strong>查看隧道客户端详情</strong>。Tab 包括 <strong>基本信息</strong>（名称、描述、状态、备注）、<strong>连接配置</strong>（服务器地址、端口、认证令牌、TLS 等）、<strong>高级配置</strong>（自动重连、重试与心跳等）。查看模式下为只读，确认不提交写操作。</p><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p><img src="'+d+'" alt="客户端列表右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据</strong> / <strong>复制单元格</strong></td><td>表格内置。</td></tr><tr><td><strong>查看详情</strong></td><td>只读打开客户端表单。</td></tr><tr><td><strong>编辑</strong></td><td>拉取最新详情后进入编辑。</td></tr><tr><td><strong>连接</strong> / <strong>断开连接</strong></td><td>对当前行执行连接或断开。</td></tr><tr><td><strong>删除</strong></td><td>删除当前行对应客户端。</td></tr></tbody></table><hr><h2 id="服务管理" tabindex="-1">服务管理 <a class="header-anchor" href="#服务管理" aria-label="Permalink to &quot;服务管理&quot;">​</a></h2><h3 id="加载与统计-1" tabindex="-1">加载与统计 <a class="header-anchor" href="#加载与统计-1" aria-label="Permalink to &quot;加载与统计&quot;">​</a></h3><ul><li>切换到 <strong>服务管理</strong> 时，挂载阶段会拉取 <strong>统计卡片</strong>（总服务数、活动服务、不活动服务、错误服务、离线服务、总连接数）。</li><li><strong>服务列表</strong> 需在点击 <strong>查询</strong> 后加载（与 <code>TunnelServiceManagement</code> 注释一致）；<strong>重置</strong> 清空筛选后再查询可刷新列表。</li><li>每次 <strong>查询</strong> 成功后会再次刷新统计。</li></ul><p><img src="'+e+'" alt="服务管理：筛选、统计与服务列表"></p><h3 id="筛选项-1" tabindex="-1">筛选项 <a class="header-anchor" href="#筛选项-1" aria-label="Permalink to &quot;筛选项&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务名称</strong></td><td>占位：请输入服务名称。</td></tr><tr><td><strong>服务类型</strong></td><td>下拉：TCP / UDP / HTTP / HTTPS / STCP / SUDP / XTCP 等（与配置项一致）。</td></tr><tr><td><strong>服务状态</strong></td><td>下拉：<strong>活动</strong> / <strong>不活动</strong> / <strong>错误</strong> / <strong>离线</strong>。</td></tr><tr><td><strong>关键词</strong></td><td>占位：服务名称/本地地址/子域名，用于组合检索。</td></tr></tbody></table><h3 id="工具栏-1" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏-1" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增服务</strong></td><td>打开「新增隧道服务」表单弹窗。</td></tr><tr><td><strong>查询</strong> / <strong>重置</strong></td><td>与筛选表单联动。</td></tr></tbody></table><p><strong>编辑</strong>、<strong>删除</strong> 请使用表格 <strong>右键菜单</strong>（当前工具栏未提供独立的编辑、删除按钮）。</p><h3 id="表格列-主要-1" tabindex="-1">表格列（主要） <a class="header-anchor" href="#表格列-主要-1" aria-label="Permalink to &quot;表格列（主要）&quot;">​</a></h3><p>含 <strong>勾选</strong> 与 <strong>序号</strong>。列包括：<strong>服务 ID</strong>、<strong>服务名称</strong>、<strong>客户端 ID</strong>、<strong>服务类型</strong>（标签）、<strong>本地地址</strong>（本地 IP 与本地端口拼接）、<strong>远程端口</strong>、<strong>子域名</strong>、<strong>服务状态</strong>（活动/不活动/错误/离线 等标签）、<strong>当前连接</strong>、<strong>总连接数</strong>、<strong>注册时间</strong>、<strong>最后活动</strong>、<strong>状态</strong>（启用/禁用标签）等；底部分页。</p><h3 id="新增-编辑隧道服务表单" tabindex="-1">新增 / 编辑隧道服务表单 <a class="header-anchor" href="#新增-编辑隧道服务表单" aria-label="Permalink to &quot;新增 / 编辑隧道服务表单&quot;">​</a></h3><p>弹窗标题为 <strong>新增隧道服务</strong>、<strong>编辑隧道服务</strong>、<strong>查看隧道服务详情</strong>。分为三个 Tab：<strong>基础信息</strong>、<strong>地址配置</strong>、<strong>高级配置</strong>。</p><p><strong>基础信息</strong> 示例（节选）：</p><p><img src="'+h+'" alt="新增隧道服务 - 基础信息"></p><ul><li><strong>服务名称</strong>（必填）、<strong>服务描述</strong>、<strong>客户端 ID</strong>（必填）：可手输，或点击右侧 <strong>…</strong> 打开 <strong>选择客户端</strong> 对话框。</li><li><strong>服务类型</strong>（必填）、<strong>激活状态</strong>（启用/禁用）、<strong>备注</strong> 等。</li></ul><p><strong>选择客户端</strong> 弹窗标题为 <strong>选择客户端</strong>，表格中可查看客户端 ID、名称、服务器地址、连接状态、状态等；<strong>单击行</strong> 选择并回填客户端 ID。</p><p><img src="'+l+'" alt="选择客户端"></p><p><strong>地址配置</strong> Tab 示例：</p><p><img src="'+i+'" alt="新增隧道服务 - 地址配置"></p><ul><li><strong>本地地址</strong>、<strong>本地端口</strong>（必填）。</li><li><strong>远程端口</strong>（可选，占位说明由服务器分配时可留空或按提示填写）。</li><li><strong>子域名</strong>、<strong>自定义域名</strong>（多域名逗号分隔）等，用于 HTTP/HTTPS 类场景。</li></ul><p><strong>高级配置</strong> 中含加密、压缩、密钥、最大连接数、带宽限制、HTTP 认证、Host 头重写、健康检查等字段（以表单实际展示为准）。</p><h3 id="右键菜单-服务" tabindex="-1">右键菜单（服务） <a class="header-anchor" href="#右键菜单-服务" aria-label="Permalink to &quot;右键菜单（服务）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>只读查看服务配置。</td></tr><tr><td><strong>注册服务</strong></td><td>向运行环境注册当前服务（若后端支持）。</td></tr><tr><td><strong>注销服务</strong></td><td>注销运行态服务。</td></tr><tr><td><strong>编辑</strong></td><td>拉取详情后编辑。</td></tr><tr><td><strong>删除</strong></td><td>删除该条服务配置。</td></tr><tr><td><strong>复制行数据</strong> / <strong>复制单元格</strong></td><td>表格内置。</td></tr></tbody></table><hr><h2 id="与-hub0060-hub0061-的关系" tabindex="-1">与 hub0060 / hub0061 的关系 <a class="header-anchor" href="#与-hub0060-hub0061-的关系" aria-label="Permalink to &quot;与 hub0060 / hub0061 的关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>关系</th></tr></thead><tbody><tr><td><strong><a href="./hub0060.html">hub0060</a></strong></td><td>隧道 <strong>服务端</strong> 部署与运行态；本页客户端的 <strong>服务器地址、端口、认证信息</strong> 必须与 hub0060 中该实例的监听及安全配置一致，否则无法建立控制连接或注册服务。</td></tr><tr><td><strong><a href="./hub0061.html">hub0061</a></strong></td><td><strong>静态映射</strong> 在网关/服务端侧做多后端负载与端口策略（与架构图中「静态映射」示意对应）；与本页由 <strong>隧道客户端动态注册</strong> 的 <strong>隧道服务</strong> 是不同配置路径，可按架构组合使用。</td></tr></tbody></table>',57)])])}const T=r(b,[["render",u]]);export{f as __pageData,T as default};
